import React from 'react';

const Categorias = ({ categoriaAtual, onCategoriaChange }) => {
  const categorias = [
    { id: 'todos', nome: 'Todos' },
    { id: 'bebida', nome: 'Bebidas' },
    { id: 'cigarro', nome: 'Cigarros' },
    { id: 'carta', nome: 'Cartas' },
    { id: 'acessorio', nome: 'Acessórios' }
  ];

  return (
    <div className="categorias">
      {categorias.map(cat => (
        <button 
          key={cat.id}
          onClick={() => onCategoriaChange(cat.id)}
          className={categoriaAtual === cat.id ? 'ativo' : ''}
        >
          {cat.nome}
        </button>
      ))}
    </div>
  );
};

export default Categorias;
